insight.code_example:
mutation {
  marketCreate(
    input: {
      name: "US Market"
      currencyCode: USD
      shippingOptions: [
        {
          zone: {
            name: "Contiguous US"
            countries: [US]
          }
          rate: {
            price: 10.00
          }
        }
      ]
    }
  ) {
    market {
      id
      name
    }
  }
}
